#!/bin/sh
# Nomad Bootstrap — srv2 (server)
# Generated by CI — DO NOT EDIT

set -e

# ---- Args ----
REINSTALL=0
while [ $# -gt 0 ]; do
  case "$1" in
    --gossip-key) GOSSIP_KEY="$2"; shift 2 ;;
    --seed-addr)  SEED_ADDR="$2";  shift 2 ;;
    --reinstall)  REINSTALL=1; shift ;;
    *) echo "Usage: $0 --gossip-key <key> --seed-addr <ip> [--reinstall]"; exit 1 ;;
  esac
done
[ -z "$GOSSIP_KEY" ] && { echo "ERROR: --gossip-key required"; exit 1; }
[ -z "$SEED_ADDR" ]  && { echo "ERROR: --seed-addr required"; exit 1; }

echo "=== Nomad Bootstrap: srv2 (server) ==="

# ---- OS check ----
command -v pkg >/dev/null 2>&1 || { echo "ERROR: FreeBSD required"; exit 1; }
echo "✓ FreeBSD"

# ---- Reinstall (optional) ----
if [ "$REINSTALL" = 1 ]; then
  echo "⚠  REINSTALL: stopping Nomad and purging data"
  service nomad stop 2>/dev/null || true
  rm -rf /opt/nomad/data /etc/nomad.d
  echo "✓ Data purged"
fi

# ---- Install ----
if command -v nomad >/dev/null 2>&1; then
  echo "✓ Nomad: $(nomad version | head -1)"
else
  echo "→ pkg install nomad..."
  pkg install -y nomad
fi
mkdir -p /opt/nomad/data /etc/nomad.d

# ---- Config ----
cat > /etc/nomad.d/server.hcl << 'NMD'
datacenter = "dc1"
name       = "srv2"
data_dir   = "/opt/nomad"

server {
  enabled    = true
  retry_join = ["SEED_ADDR_PLACEHOLDER:4648"]
  encrypt    = "GOSSIP_KEY_PLACEHOLDER"
}
client {
  enabled = true
  options { "driver.raw_exec.enable" = "1" }
}

NMD

# ---- Inject key & addr ----
sed -i '' "s/GOSSIP_KEY_PLACEHOLDER/${GOSSIP_KEY}/" /etc/nomad.d/server.hcl
sed -i '' "s/SEED_ADDR_PLACEHOLDER:4648/${SEED_ADDR}:4648/" /etc/nomad.d/server.hcl

# ---- Start ----
sysrc nomad_enable=YES
sysrc nomad_args="-config=/etc/nomad.d"
service nomad status >/dev/null 2>&1 && service nomad restart || service nomad start

# ---- Wait ----
for i in $(seq 1 60); do
  nomad server members 2>/dev/null | grep -q alive && break
  sleep 1
done

echo "✓ srv2 ready"